src/MainWalletRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract MainWalletRegistry is Ownable {
    mapping(address => bool) private _registered;
    address[] private _wallets;

    event WalletRegistered(address indexed wallet);
    event WalletRemoved(address indexed wallet);

    constructor() Ownable(msg.sender) {}

    function registerMainWallet(address wallet) external onlyOwner {
        require(wallet != address(0), "Invalid address");
        require(!_registered[wallet], "Already registered");

        _registered[wallet] = true;
        _wallets.push(wallet);

        emit WalletRegistered(wallet);
    }

    function removeMainWallet(address wallet) external onlyOwner {
        require(_registered[wallet], "Not registered");

        _registered[wallet] = false;

        for (uint256 i = 0; i < _wallets.length; i++) {
            if (_wallets[i] == wallet) {
                _wallets[i] = _wallets[_wallets.length - 1];
                _wallets.pop();
                break;
            }
        }

        emit WalletRemoved(wallet);
    }

    function isRegistered(address wallet) external view returns (bool) {
        return _registered[wallet];
    }

    function getWallets() external view returns (address[] memory) {
        return _wallets;
    }

    function walletCount() external view returns (uint256) {
        return _wallets.length;
    }
}

