// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract ManagedTokenDistributor {
    using SafeERC20 for IERC20;

    address public immutable tokenOut;
    uint256 public immutable amount;
    address public immutable recipient;
    address public immutable owner;
    bool public executed;

    event Executed(address indexed token, uint256 amount, address indexed recipient);
    event TokensRescued(address indexed token, uint256 amount, address indexed to);

    error OnlyOwner();
    error AlreadyExecuted();
    error InsufficientBalance(uint256 available, uint256 required);

    constructor(
        address _tokenOut,
        uint256 _amount,
        address _recipient,
        address _owner
    ) {
        require(_tokenOut != address(0), "Invalid token address");
        require(_amount > 0, "Amount must be greater than 0");
        require(_recipient != address(0), "Invalid recipient address");
        require(_owner != address(0), "Invalid owner address");

        tokenOut = _tokenOut;
        amount = _amount;
        recipient = _recipient;
        owner = _owner;
    }

    modifier onlyOwner() {
        if (msg.sender != owner) revert OnlyOwner();
        _;
    }

    function execute() external onlyOwner {
        if (executed) revert AlreadyExecuted();

        uint256 balance = IERC20(tokenOut).balanceOf(address(this));
        if (balance < amount) revert InsufficientBalance(balance, amount);

        executed = true;
        IERC20(tokenOut).safeTransfer(recipient, amount);

        emit Executed(tokenOut, amount, recipient);
    }

    function rescueTokens(address token) external onlyOwner {
        uint256 balance = IERC20(token).balanceOf(address(this));
        require(balance > 0, "No tokens to rescue");

        IERC20(token).safeTransfer(owner, balance);

        emit TokensRescued(token, balance, owner);
    }

    function getConfig()
        external
        view
        returns (
            address _tokenOut,
            uint256 _amount,
            address _recipient,
            address _owner,
            bool _executed
        )
    {
        return (tokenOut, amount, recipient, owner, executed);
    }
}

src/SubWalletRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract SubWalletRegistry is Ownable {
    mapping(address => address[]) private _subWallets;
    mapping(address => address) private _parent;

    event SubWalletRegistered(address indexed mainWallet, address indexed subWallet);

    constructor() Ownable(msg.sender) {}

    function registerSubWallet(address mainWallet, address subWallet) external onlyOwner {
        require(mainWallet != address(0), "Invalid main wallet");
        require(subWallet != address(0), "Invalid sub wallet");
        require(_parent[subWallet] == address(0), "Sub wallet already registered");

        _parent[subWallet] = mainWallet;
        _subWallets[mainWallet].push(subWallet);

        emit SubWalletRegistered(mainWallet, subWallet);
    }

    function getSubWallets(address mainWallet) external view returns (address[] memory) {
        return _subWallets[mainWallet];
    }

    function getParent(address subWallet) external view returns (address) {
        return _parent[subWallet];
    }

    function subWalletCount(address mainWallet) external view returns (uint256) {
        return _subWallets[mainWallet].length;
    }
}

