// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

contract TokenConfigRegistry is Ownable {
    struct TokenInfo {
        address tokenAddress;
        uint8 decimals;
        bool isActive;
    }

    mapping(bytes32 => TokenInfo) private _tokens;
    string[] private _symbols;
    mapping(bytes32 => bool) private _symbolExists;

    event TokenSet(string symbol, address tokenAddress, uint8 decimals);
    event TokenDeactivated(string symbol);
    event TokenActivated(string symbol);

    constructor() Ownable(msg.sender) {}

    function setToken(
        string calldata symbol,
        address tokenAddress,
        uint8 decimals
    ) external onlyOwner {
        require(tokenAddress != address(0), "Invalid token address");

        bytes32 key = keccak256(abi.encodePacked(symbol));

        if (!_symbolExists[key]) {
            _symbols.push(symbol);
            _symbolExists[key] = true;
        }

        _tokens[key] = TokenInfo({
            tokenAddress: tokenAddress,
            decimals: decimals,
            isActive: true
        });

        emit TokenSet(symbol, tokenAddress, decimals);
    }

    function deactivateToken(string calldata symbol) external onlyOwner {
        bytes32 key = keccak256(abi.encodePacked(symbol));
        require(_symbolExists[key], "Token not found");

        _tokens[key].isActive = false;

        emit TokenDeactivated(symbol);
    }

    function activateToken(string calldata symbol) external onlyOwner {
        bytes32 key = keccak256(abi.encodePacked(symbol));
        require(_symbolExists[key], "Token not found");

        _tokens[key].isActive = true;

        emit TokenActivated(symbol);
    }

    function getToken(string calldata symbol)
        external
        view
        returns (address tokenAddress, uint8 decimals, bool isActive)
    {
        bytes32 key = keccak256(abi.encodePacked(symbol));
        TokenInfo memory info = _tokens[key];
        return (info.tokenAddress, info.decimals, info.isActive);
    }

    function getAllActiveTokens()
        external
        view
        returns (string[] memory symbols, address[] memory addresses, uint8[] memory decimals)
    {
        uint256 activeCount = 0;
        for (uint256 i = 0; i < _symbols.length; i++) {
            bytes32 key = keccak256(abi.encodePacked(_symbols[i]));
            if (_tokens[key].isActive) {
                activeCount++;
            }
        }

        symbols = new string[](activeCount);
        addresses = new address[](activeCount);
        decimals = new uint8[](activeCount);

        uint256 idx = 0;
        for (uint256 i = 0; i < _symbols.length; i++) {
            bytes32 key = keccak256(abi.encodePacked(_symbols[i]));
            if (_tokens[key].isActive) {
                symbols[idx] = _symbols[i];
                addresses[idx] = _tokens[key].tokenAddress;
                decimals[idx] = _tokens[key].decimals;
                idx++;
            }
        }
    }
}

